INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2210-0001-0000-0000-000000000000', '7a245639-e051-4c8c-9bf3-24aaea257ab1', 'text', '{"html":"<h3>What mine surveying is</h3><p><strong>Mine surveying</strong> is the branch of surveying that lays out, controls, and records mining excavations &mdash; surface pits and underground workings alike &mdash; and ties them to a common coordinate and grade system. The mine surveyor establishes <strong>surface control</strong> (a network of horizontal and vertical monuments over the property and around the shafts or portals), then carries that control into the workings so that drifts, raises, stopes, and tunnels are driven to the correct <strong>position, grade, and direction</strong>. Accuracy matters acutely underground: a drift driven on a slightly wrong azimbut over a kilometre can miss its target by metres, and two headings advancing toward each other (a <em>holing-through</em>) must meet within tight tolerances both in line and in level.</p><p>Mine surveying also produces the legal and engineering record of the mine: plans of the workings relative to the surface, lease and claim boundaries, ore reserves and extracted volumes, and proximity to neighbouring mines, old workings, and water bodies. Many jurisdictions require a licensed surveyor to maintain accurate, up-to-date mine plans for safety and regulatory reasons.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2210-0001-0000-0000-000000000001', '7a245639-e051-4c8c-9bf3-24aaea257ab1', 'text', '{"html":"<h3>Surface vs. underground control</h3><p>On the surface, the mine surveyor enjoys GNSS, long sight lines, and conventional traversing to build a strong control network. <strong>Underground control</strong> is harder: there is no GNSS, sight lines are short and obstructed, the environment is dark, wet, dusty, and the only practical link to the surface network is through the <strong>shaft</strong> (a vertical or steeply inclined opening) or an adit/portal. The fundamental problem is the <strong>correlation (connection) survey</strong> &mdash; transferring <em>both position and azimuth</em> from the surface network down into the workings.</p><p>Transferring <em>position</em> (the X, Y of a point underground) is relatively straightforward by plumbing. Transferring <em>azimuth</em> (the orientation of the underground traverse) is the classic difficulty: a vertical shaft offers almost no horizontal geometry, so a short baseline at the shaft bottom must control the direction of an entire underground traverse. Small errors in the transferred azimuth swing the far end of long drifts by large amounts, which is why orientation is given special methods and redundancy.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2210-0001-0000-0000-000000000002', '7a245639-e051-4c8c-9bf3-24aaea257ab1', 'text', '{"html":"<h3>Shaft plumbing</h3><p><strong>Shaft plumbing</strong> physically (or optically) extends a vertical line from the surface to the shaft bottom so coordinates can be carried down. In classic <strong>wire plumbing</strong>, fine high-tensile wires carrying heavy plumb-bobs are suspended down the shaft, the bobs damped in oil or water tanks to steady them; the surveyor coordinates the wires at the top (in the surface system) and reads them at the bottom, giving two underground points of known coordinates. <strong>Optical and laser plumbing</strong> uses a precise vertical-collimating instrument (an autoplumb or plumbing laser) projecting a vertical line down the shaft to a target at the bottom &mdash; faster and free of wire sway, now the common method. Either way the goal is the same: deliver one or two points of known surface coordinates to the bottom of the shaft.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2210-0001-0000-0000-000000000003', '7a245639-e051-4c8c-9bf3-24aaea257ab1', 'equation', '{"latex":"\\text{Azimuth}_{underground} = \\text{Azimuth}_{surface\\ baseline}\\ \\text{(carried down the shaft)}","label":"Goal of a correlation survey: transfer position AND azimuth underground","display":"block"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2210-0001-0000-0000-000000000004', '7a245639-e051-4c8c-9bf3-24aaea257ab1', 'text', '{"html":"<h3>The Weisbach (two-wire) method and the gyrotheodolite</h3><p>To transfer <strong>azimuth</strong>, two plumb wires are hung in the shaft a short distance apart, defining a near-vertical plane whose horizontal trace is a tiny baseline of known surface azimuth. Because the two wires sit very close together, a theodolite at the shaft bottom cannot occupy the line directly; instead the surveyor sets up slightly off-line and forms the very thin <strong>Weisbach triangle</strong>, in which a tiny measured angle at the instrument is scaled by the ratio of side lengths to recover the wire-to-wire direction with high precision. The transferred direction then orients the underground traverse.</p><p>An independent and now widely used alternative is the <strong>gyrotheodolite</strong> (gyro-theodolite or surveying gyroscope), which senses the Earth&rsquo;s rotation to find <strong>true north directly underground</strong> &mdash; no shaft geometry required. A gyro azimuth provides a powerful, independent check on (or replacement for) the Weisbach transfer, and is essential for long tunnels where a wire transfer would be impractical.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2210-0001-0000-0000-000000000005', '7a245639-e051-4c8c-9bf3-24aaea257ab1', 'callout', '{"type":"info","text":"Why orientation is the crux: a 20-arc-second azimuth error swings the far end of a 1,000 m drift by about 0.1 m, and a 1-arc-minute error by roughly 0.3 m. Position can be checked by re-plumbing; a bad transferred azimuth quietly corrupts the entire underground traverse — hence redundant transfers (two-wire AND gyro)."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2210-0001-0000-0000-000000000006', '7a245639-e051-4c8c-9bf3-24aaea257ab1', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Correlation survey down a shaft — two plumb wires carry surface coordinates and azimuth down; a Weisbach triangle recovers the wire-to-wire direction at the bottom."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2210-0001-0000-0000-000000000007', '7a245639-e051-4c8c-9bf3-24aaea257ab1', 'key_takeaways', '{"title":"Key Takeaways","items":["Mine surveying ties surface control to underground workings for correct position, grade, and direction.","The correlation (connection) survey transfers position AND azimuth down a shaft — orientation is the hard part.","Shaft plumbing (wires or laser/optical autoplumb) carries surface coordinates to the shaft bottom.","Azimuth is transferred by the two-wire Weisbach method and/or checked independently with a gyrotheodolite.","Small azimuth errors at the shaft propagate into large position errors at the far end of long drifts."]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2210-0002-0000-0000-000000000000', '5068d3ab-7f1e-41d8-ba6e-cbc1864c54e3', 'text', '{"html":"<h3>Traversing underground</h3><p>Once control is connected to the workings, the surveyor extends it with an <strong>underground traverse</strong> &mdash; a chain of measured angles and distances along the drifts. Stations are commonly fixed in the <strong>roof (back)</strong> rather than the floor, because the floor is disturbed by traffic, muck, and water; a <strong>spad</strong> (a special hook-eye nail) is driven into the roof and a <strong>plumb bob</strong> is hung from it to bring the station down to instrument height. Sights are short and obstructed, lighting is by lamp, and the instrument and targets are kept on line by <strong>forced centering</strong> (tribrachs swapped on fixed tripods/wall brackets) to minimize centering error over many short legs. Because legs are short, centering and pointing errors dominate, so careful instrument work and redundant ties are essential.</p><p>Distances are measured with EDM or steel tape; modern practice uses a <strong>total station</strong> sighting reflective targets or prisms hung from the roof spads. Each new station is computed from the previous one and periodically checked against an independent azimuth (gyro) and against re-plumbed shaft coordinates.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2210-0002-0000-0000-000000000001', '5068d3ab-7f1e-41d8-ba6e-cbc1864c54e3', 'text', '{"html":"<h3>Giving line and grade to a heading</h3><p>The surveyor&rsquo;s product underground is <strong>line and grade</strong> for the working faces. <strong>Line</strong> (the horizontal direction the heading is to be driven) is marked by setting at least two, preferably three, roof spads on the design centerline; the miners sight or string between them, or a <strong>laser</strong> mounted on the spads projects a bright line straight down the drift onto the face. <strong>Grade</strong> (the design slope of the floor or the tunnel invert) is given by setting <strong>grade pegs/spads</strong> at a fixed offset above (or below) the design surface, or by tilting the laser to the design slope so the spot rises/falls correctly along the drive. The miners then excavate to keep the face on the laser line and the floor parallel to the grade marks.</p><p>Many drifts and inclines are intentionally sloped &mdash; for drainage (gravity dewatering), for haulage (loaded cars running downgrade), or to follow an ore body &mdash; so the surveyor frequently computes and sets a specific grade rather than a level floor.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2210-0002-0000-0000-000000000002', '5068d3ab-7f1e-41d8-ba6e-cbc1864c54e3', 'text', '{"html":"<h3>Grade of an incline</h3><p>An <strong>incline</strong> (or inclined drift/decline) is described by its <strong>grade</strong>, expressed either as an <strong>angle of inclination</strong> or as a <strong>percent grade</strong>. From the vertical <em>rise</em> and the horizontal <em>run</em> between two stations, the angle is &theta; = atan2(rise, run) (in degrees), and the percent grade is rise/run &times; 100. A floor that rises 6 m over 100 m of horizontal run has a grade of about 3.43&deg;, or 6%. Mine surveyors routinely convert between the two because designers specify decline ramps in percent (e.g., a 1:7 or roughly 14% haulage decline) while the instrument reads vertical angles in degrees. The slope distance along the incline relates to run by run = slope &times; cos&theta;, and rise by rise = slope &times; sin&theta; &mdash; useful when reducing measured slope distances to plan distance and elevation difference.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2210-0002-0000-0000-000000000003', '5068d3ab-7f1e-41d8-ba6e-cbc1864c54e3', 'equation', '{"latex":"\\theta = \\operatorname{atan2}(\\text{rise},\\,\\text{run})\\quad,\\qquad \\text{grade}\\% = \\frac{\\text{rise}}{\\text{run}}\\times 100","label":"Grade of an incline — as an angle (degrees) and as a percent","display":"block"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2210-0002-0000-0000-000000000004', '5068d3ab-7f1e-41d8-ba6e-cbc1864c54e3', 'table', '{"headers":["Underground tool/term","What it does","Note"],"rows":[["Spad (roof hook-eye nail)","Fixes a survey/control station in the back (roof)","Hang a plumb bob to bring it to instrument height"],["Plumb bob from spad","Transfers the roof point down for sighting","Damp the bob to steady it"],["Forced centering","Swap tribrachs on fixed tripods/brackets","Cuts centering error over short legs"],["Laser line","Projects line (and tilted, grade) down the drift","Miners keep the face on the spot"],["Grade peg / grade spad","Marks a fixed offset to the design grade","Sets floor/invert slope"]]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2210-0002-0000-0000-000000000005', '5068d3ab-7f1e-41d8-ba6e-cbc1864c54e3', 'callout', '{"type":"warning","text":"Watch the sights, not just the math: underground legs are short, so centering and pointing errors — not distance error — dominate the traverse. Use forced centering, observe each angle on both faces, and re-orient with a gyro azimuth periodically; otherwise the swing in azimuth over a long drive can put a holing-through out of tolerance."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2210-0002-0000-0000-000000000006', '5068d3ab-7f1e-41d8-ba6e-cbc1864c54e3', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Setting line and grade in a drift — roof spads define the centerline, a laser projects line to the face, and grade pegs set the floor slope."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2210-0002-0000-0000-000000000007', '5068d3ab-7f1e-41d8-ba6e-cbc1864c54e3', 'key_takeaways', '{"title":"Key Takeaways","items":["Underground traverses use roof spads with hung plumb bobs, short obstructed sights, and forced centering.","Line is set by spads/laser on the centerline; grade is set by grade pegs or a tilted laser to the design slope.","Grade of an incline = atan2(rise, run) in degrees, or rise/run × 100 as a percent.","Convert slope distance with run = slope·cosθ and rise = slope·sinθ.","Periodic gyro azimuths bound the orientation error that accumulates over long drives."]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2210-0003-0000-0000-000000000000', '2a2f13a3-eaf6-424f-a469-c84dfae6951b', 'text', '{"html":"<h3>Mining-induced subsidence</h3><p>Removing ore or coal underground (especially by caving or longwall methods) leaves voids into which the overlying rock relaxes and settles, lowering the ground surface above &mdash; <strong>mining-induced subsidence</strong>. The surface response ranges from a broad, gentle <strong>sag (subsidence trough)</strong> over a wide extraction panel, to sharp, dangerous <strong>sinkholes</strong> and <strong>step (fault) scarps</strong> where shallow workings or pillars collapse. Subsidence can crack buildings, shear pipelines and rail, alter drainage and flooding, and endanger people, so mines are typically required to <strong>predict, monitor, and report</strong> surface movement above active and abandoned workings.</p><p>The mine surveyor establishes <strong>monitoring lines</strong> &mdash; rows of stable, well-monumented points crossing the predicted trough (often a centreline transverse to the panel plus a longitudinal line) &mdash; and observes them repeatedly. Each round of observation is an <strong>epoch</strong>; comparing epochs reveals how much each point has moved vertically (settlement) and horizontally (strain), and how the trough develops as mining advances.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2210-0003-0000-0000-000000000001', '2a2f13a3-eaf6-424f-a469-c84dfae6951b', 'text', '{"html":"<h3>Observing and reducing the movement</h3><p>Vertical movement is the primary subsidence quantity and is measured by <strong>precise (geodetic) levelling</strong> of the monitoring points back to deep, stable reference benchmarks well outside the influence zone, or by repeated static <strong>GNSS</strong>. The <strong>settlement</strong> of a point between two epochs is simply its earlier elevation minus its later elevation: &Delta;H = H<sub>epoch1</sub> &minus; H<sub>epoch2</sub> (a positive value is downward movement). Horizontal movements give <strong>strain</strong> (change in distance between adjacent points divided by their spacing), which is what actually damages rigid structures and pipelines. Results are plotted as subsidence profiles and contoured to show the trough, and compared against predicted (influence-function) values and against damage thresholds.</p><p>Reliability hinges on the <strong>reference frame</strong>: the datum benchmarks must lie outside the subsidence basin, and the network must be redundant and adjusted so that real ground movement is not confused with instrument or datum error. Tight, repeatable procedures (same setups, same routes) let small movements be detected with confidence.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2210-0003-0000-0000-000000000002', '2a2f13a3-eaf6-424f-a469-c84dfae6951b', 'equation', '{"latex":"\\Delta H = H_{epoch\\,1} - H_{epoch\\,2}\\qquad(\\text{positive} = \\text{settlement / downward})","label":"Vertical movement (settlement) of a monitoring point between two epochs","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2210-0003-0000-0000-000000000003', '2a2f13a3-eaf6-424f-a469-c84dfae6951b', 'text', '{"html":"<h3>Volumes — stockpiles and pits</h3><p>Mine surveyors are constantly asked &lsquo;how much?&rsquo; &mdash; the volume of an ore or waste <strong>stockpile</strong>, the material removed from a <strong>pit</strong> this month, or the void left by extraction. The classic field method is the <strong>average-end-area</strong> method: parallel cross-sections are cut through the pile/pit at a regular spacing L, the area of each section (A<sub>1</sub>, A<sub>2</sub>, &hellip;) is measured, and the volume between two adjacent sections is the average of their end areas times the spacing, V = (A<sub>1</sub> + A<sub>2</sub>)/2 &times; L, summed along the body. For a single prism between two sections this is exact for a linear change in area and a good approximation otherwise.</p><p>Today the same volumes are usually computed by <strong>surface differencing</strong>: a <strong>UAV (drone) photogrammetry</strong> or <strong>laser-scan</strong> survey builds a dense 3D surface of the pile, which is compared to a base/ground surface, and the software integrates the height difference over the footprint. UAV surveys are fast, safe (no climbing piles), and dense; average-end-area remains the hand-check and the method behind cross-section earthwork reports.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2210-0003-0000-0000-000000000004', '2a2f13a3-eaf6-424f-a469-c84dfae6951b', 'equation', '{"latex":"V = \\frac{A_1 + A_2}{2}\\,L","label":"Average-end-area volume between two cross-sections spaced L apart","display":"block"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2210-0003-0000-0000-000000000005', '2a2f13a3-eaf6-424f-a469-c84dfae6951b', 'table', '{"headers":["Technique","Best for","Note"],"rows":[["Precise levelling","Vertical subsidence of monitoring points","Tie to deep BMs outside the basin"],["Static / repeated GNSS","3D movement of open monitoring points","Needs sky view; mm-level over time"],["Robotic total station","Continuous, automated point monitoring","Auto-targets near critical structures"],["UAV photogrammetry / LiDAR","Stockpile & pit volumes, broad surfaces","Dense surface; difference to base"],["Satellite InSAR","Wide-area, mm subsidence over time","No ground marks; weather/coherence limits"]]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2210-0003-0000-0000-000000000006', '2a2f13a3-eaf6-424f-a469-c84dfae6951b', 'callout', '{"type":"warning","text":"Datum outside the basin: subsidence results are only as good as the reference frame. If a ''stable'' benchmark is itself inside the influence zone and sinking, the survey will under-report movement. Always tie monitoring to deep, distant benchmarks proven stable, and carry redundant ties so datum motion can be detected."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2210-0003-0000-0000-000000000007', '2a2f13a3-eaf6-424f-a469-c84dfae6951b', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: A subsidence trough monitored by a line of levelled points (left), and a stockpile sliced into end-area cross-sections for volume (right)."}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2210-0003-0000-0000-000000000008', '2a2f13a3-eaf6-424f-a469-c84dfae6951b', 'key_takeaways', '{"title":"Key Takeaways","items":["Underground extraction causes surface subsidence — broad troughs to sinkholes — that must be predicted and monitored.","Vertical movement between epochs is ΔH = H_epoch1 − H_epoch2; horizontal movement gives damaging strain.","Reference benchmarks must lie outside the subsidence basin and be proven stable.","Stockpile/pit volume by average end area: V = (A1 + A2)/2 × L, summed along the body.","UAV photogrammetry/LiDAR and InSAR now provide dense, fast, safe volume and subsidence data."]}'::jsonb, 8);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2210-0004-0000-0000-000000000000', '1842b5e3-a8d9-43d7-9972-5b585eff182c', 'text', '{"html":"<h3>From surveying to dimensional metrology</h3><p><strong>Industrial (dimensional) metrology</strong> applies the measurement science of surveying &mdash; angles, distances, coordinates, and least-squares adjustment &mdash; to the alignment and inspection of <strong>machines, structures, and manufactured assemblies</strong>. Where field surveying works at the millimetre-to-centimetre level over metres-to-kilometres, industrial metrology works at the <strong>micrometre-to-tenth-of-millimetre level</strong> over millimetres-to-tens-of-metres. The same person who can build a precise control network is well-suited to align a paper-machine drive train, set the rolls of a rolling mill, level a turbine, or position the magnets of a particle accelerator.</p><p><strong>Large-scale metrology</strong> is the subfield handling objects too large for a benchtop coordinate-measuring machine (CMM): aircraft fuselages and wings, ship sections, wind-turbine and generator assemblies, antennas, and accelerator tunnels. It uses portable, high-accuracy instruments &mdash; laser trackers, industrial total stations, photogrammetry, and laser scanners &mdash; brought to the object, with results tied into a single, rigorously defined <strong>reference frame</strong>.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2210-0004-0000-0000-000000000001', '1842b5e3-a8d9-43d7-9972-5b585eff182c', 'text', '{"html":"<h3>The instruments</h3><p>The flagship instrument is the <strong>laser tracker</strong>: a servo-driven head that locks an interferometer/ADM laser onto a <strong>spherically mounted retroreflector (SMR)</strong> and continuously reports the 3D coordinates of the SMR as an operator walks it over the object, achieving accuracies of a few micrometres per metre. Trackers measure flatness, straightness, bore alignment, and build full point clouds of large parts. The <strong>industrial total station</strong> (a high-precision theodolite/EDM) and <strong>close-range photogrammetry</strong> serve similar large-scale tasks, often combined.</p><p>For pure <strong>straightness and squareness</strong>, optical methods remain unbeaten: a <strong>laser alignment line</strong> (or a precise optical line of sight from an alignment telescope) provides a straight reference against which targets are read for offset, while an <strong>autocollimator</strong> measures tiny <strong>angular</strong> deviations &mdash; the tilt or twist of a mirror/face &mdash; to fractions of an arc-second, used to check the flatness of ways, the squareness of machine axes, and the angular wander of a surface. <strong>Precision spirit/electronic levels</strong> verify level and small slopes to a few arc-seconds.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2210-0004-0000-0000-000000000002', '1842b5e3-a8d9-43d7-9972-5b585eff182c', 'table', '{"headers":["Instrument","Measures","Typical use"],"rows":[["Laser tracker (with SMR)","3D coordinates of a moving target","Machine/assembly alignment, large-part inspection"],["Industrial total station","Angles + distance → coordinates","Large structures, monitoring, tie-ins"],["Alignment telescope / laser line","Straightness (offset from a line)","Shaft trains, bores, rolls, ways"],["Autocollimator","Small angular deviation (arc-seconds)","Flatness, squareness, angular wander"],["Precision level (electronic)","Level / small slope","Leveling beds, turbines, foundations"],["Photogrammetry / laser scanner","Dense 3D surface","Reverse engineering, deformation, as-built"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2210-0004-0000-0000-000000000003', '1842b5e3-a8d9-43d7-9972-5b585eff182c', 'text', '{"html":"<h3>Tolerances, datums, and the environment</h3><p>Industrial alignment is specified by tight geometric tolerances &mdash; <strong>straightness</strong> of a shaft line, <strong>flatness</strong> of a bed, <strong>level</strong> of a machine, <strong>coaxiality</strong> (concentricity) of bearings, and <strong>squareness</strong> of axes &mdash; often in micrometres or arc-seconds. Achieving them depends less on the headline instrument accuracy than on two things: a well-defined <strong>reference frame (datum)</strong> built from stable monuments/nests and tied with redundant, adjusted measurements, and <strong>environmental control</strong>. At these tolerances, <strong>temperature</strong> dominates: steel expands about 11.7 &micro;m per metre per &deg;C, so a 10 m machine bed grows over a tenth of a millimetre with a 1&deg;C change. Measurements are therefore referenced to 20&deg;C, taken when the structure is thermally stable, and corrected for the temperatures of both the part and the scale.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2210-0004-0000-0000-000000000004', '1842b5e3-a8d9-43d7-9972-5b585eff182c', 'equation', '{"latex":"\\Delta L = \\alpha\\, L\\, \\Delta T \\qquad (\\alpha_{steel} \\approx 11.7\\times 10^{-6}\\,/^{\\circ}\\mathrm{C})","label":"Thermal expansion — why metrology is referenced to 20°C","display":"block"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2210-0004-0000-0000-000000000005', '1842b5e3-a8d9-43d7-9972-5b585eff182c', 'callout', '{"type":"info","text":"At micrometre tolerances, temperature is the enemy. A 10 m steel assembly changes length by ~0.12 mm per 1°C. Reference everything to 20°C, let the part reach thermal equilibrium, record part and instrument temperatures, and apply scale/expansion corrections — or the alignment is wrong before you start."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2210-0004-0000-0000-000000000006', '1842b5e3-a8d9-43d7-9972-5b585eff182c', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Large-scale metrology — a laser tracker follows an SMR across a machine bed while an autocollimator checks angular deviation of the ways."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2210-0004-0000-0000-000000000007', '1842b5e3-a8d9-43d7-9972-5b585eff182c', 'key_takeaways', '{"title":"Key Takeaways","items":["Industrial/dimensional metrology aligns and inspects machines and assemblies to micrometre/tenth-mm tolerances.","Large-scale metrology measures objects too big for a CMM using trackers, total stations, and photogrammetry.","Laser trackers report 3D coordinates of a moving SMR to a few µm/m; autocollimators measure tiny angular deviations.","Alignment specs include straightness, flatness, level, coaxiality, and squareness.","The reference frame and temperature (ΔL = αLΔT) control the achievable accuracy — reference to 20°C."]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2210-0005-0000-0000-000000000000', 'da502306-8208-4fd7-9910-5bbf852044ba', 'text', '{"html":"<h3>What deformation monitoring is</h3><p>A <strong>deformation monitoring survey</strong> measures an object repeatedly over time to detect, quantify, and characterise <strong>movement</strong> &mdash; settlement, heave, tilt, convergence, or lateral creep. In mining and industry it watches <strong>open-pit slopes and highwalls, tailings dams, waste dumps, shafts and headframes, underground convergence, large machines, bridges, and buildings</strong>, providing early warning of failure and a record of long-term behaviour. The survey is organised around two classes of points: <strong>reference (datum) points</strong>, placed on ground proven stable and well outside the deforming zone, and <strong>object (target) points</strong>, fixed to the structure or ground being watched. Each round of observations is an <strong>epoch</strong>; movement is the change in an object point&rsquo;s coordinates or height between epochs, expressed in the datum frame.</p><p>The defining challenge is separating <strong>real movement</strong> from <strong>measurement noise</strong>. A computed change is only meaningful if it exceeds the survey&rsquo;s uncertainty &mdash; so monitoring networks are designed for redundancy, rigorously adjusted by least squares, and the apparent movement of each point is tested for <strong>statistical significance</strong> before it is reported as deformation.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2210-0005-0000-0000-000000000001', 'da502306-8208-4fd7-9910-5bbf852044ba', 'text', '{"html":"<h3>Significance: is the movement real?</h3><p>Because every measurement has uncertainty, the surveyor compares the observed displacement of a point against its <strong>uncertainty</strong>. A practical rule treats a movement as <strong>significant</strong> only when it exceeds about its expanded uncertainty &mdash; commonly the combined (root-sum-square) standard uncertainties of the two epochs times a coverage factor (e.g., &asymp; 2&radic;2 &sigma; for two epochs at 95%). For magnitude, the resultant horizontal movement of a point between epochs is the distance between its two positions, &delta; = hypot(&Delta;E, &Delta;N) = sqrt(&Delta;E&sup2; + &Delta;N&sup2;), and the total 3D movement adds the height change in quadrature. Reporting movement below the noise floor as &lsquo;deformation&rsquo; causes false alarms and erodes trust; failing to detect real movement is dangerous &mdash; so the statistical test, the network design, and the stability of the datum points are all critical.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2210-0005-0000-0000-000000000002', 'da502306-8208-4fd7-9910-5bbf852044ba', 'equation', '{"latex":"\\delta = \\sqrt{\\Delta E^2 + \\Delta N^2} = \\operatorname{hypot}(\\Delta E,\\,\\Delta N)","label":"Resultant horizontal displacement of an object point between two epochs","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2210-0005-0000-0000-000000000003', 'da502306-8208-4fd7-9910-5bbf852044ba', 'text', '{"html":"<h3>The sensors and how they combine</h3><p>Modern monitoring blends <strong>geodetic</strong> and <strong>geotechnical</strong> sensors. <strong>Automated (robotic) total stations</strong> cyclically sight arrays of prisms on a structure or pit wall, delivering sub-millimetre 3D positions every few minutes &mdash; the workhorse for dams, tunnels, and pit slopes near sensitive works. <strong>Continuous GNSS</strong> stations give millimetre 3D movement of open points with sky view. <strong>Satellite InSAR</strong> maps wide-area, millimetre line-of-sight movement of slopes and subsidence without any ground marks, and <strong>ground-based radar</strong> watches a moving highwall in near real time. Geotechnical instruments &mdash; <strong>tiltmeters, extensometers, crackmeters, inclinometers, and piezometers</strong> &mdash; add high-rate, localised measurement of rotation, strain, crack opening, and pore pressure. The data feed a monitoring system that flags exceedance of <strong>alert</strong> and <strong>alarm</strong> thresholds, triggering review or evacuation.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2210-0005-0000-0000-000000000004', 'da502306-8208-4fd7-9910-5bbf852044ba', 'table', '{"headers":["Sensor / method","Quantity","Typical monitoring target"],"rows":[["Automated robotic total station","3D position of prisms (sub-mm)","Pit slopes, dams, tunnels, buildings"],["Continuous GNSS","3D movement of open points (mm)","Dam crests, slope reference/object points"],["Satellite InSAR","Wide-area LOS movement (mm)","Regional slopes, subsidence basins"],["Ground-based radar","Near-real-time wall movement","Active open-pit highwalls"],["Tiltmeter / inclinometer","Rotation / sub-surface lateral movement","Walls, structures, slope masses"],["Extensometer / crackmeter","Strain / crack opening","Convergence, fractures, joints"]]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2210-0005-0000-0000-000000000005', 'da502306-8208-4fd7-9910-5bbf852044ba', 'callout', '{"type":"warning","text":"Report only significant movement. Apparent movement smaller than the combined survey uncertainty is noise, not deformation — flagging it causes false alarms; missing real movement is dangerous. Design redundant networks, adjust by least squares, prove the datum points are stable, and test each displacement for statistical significance before reporting."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2210-0005-0000-0000-000000000006', 'da502306-8208-4fd7-9910-5bbf852044ba', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: An open-pit slope monitored by a robotic total station on prisms, GNSS reference points on stable ground, and ground-based radar; vectors show inter-epoch movement."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2210-0005-0000-0000-000000000007', 'da502306-8208-4fd7-9910-5bbf852044ba', 'key_takeaways', '{"title":"Key Takeaways","items":["Deformation monitoring repeatedly surveys an object to detect and quantify movement over time.","It separates stable reference (datum) points from object points and works in epochs.","Movement is significant only when it exceeds the combined survey uncertainty (statistical test).","Resultant horizontal displacement δ = hypot(ΔE, ΔN); add ΔH in quadrature for 3D.","Robotic total stations, GNSS, InSAR, radar, and geotechnical sensors combine against alert/alarm thresholds."]}'::jsonb, 7);
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2240-0000-0000-0000-000000000001', 'Mine surveying', 'The branch of surveying that lays out, controls, and records surface and underground mine excavations and ties them to a common coordinate and grade system, producing the legal and engineering plan of the mine.', 'Surveying the workings, surface and underground.', 'c1000016-0000-0000-0000-000000000016', '7a245639-e051-4c8c-9bf3-24aaea257ab1', 'surveying', ARRAY['buildout','module-22']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2240-0000-0000-0000-000000000002', 'Correlation (connection) survey', 'The survey that transfers both position and azimuth from the surface control network down into the underground workings, usually through a shaft. Transferring azimuth (orientation) is the difficult part.', 'Tie surface control to the workings.', 'c1000016-0000-0000-0000-000000000016', '7a245639-e051-4c8c-9bf3-24aaea257ab1', 'surveying', ARRAY['buildout','module-22']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2240-0000-0000-0000-000000000003', 'Shaft plumbing', 'Extending a vertical line from the surface to the shaft bottom — by suspended plumb wires (with damped bobs) or an optical/laser autoplumb — to carry surface coordinates underground.', 'Drop a vertical line down the shaft.', 'c1000016-0000-0000-0000-000000000016', '7a245639-e051-4c8c-9bf3-24aaea257ab1', 'surveying', ARRAY['buildout','module-22']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2240-0000-0000-0000-000000000004', 'Weisbach triangle', 'A very thin triangle formed when a theodolite is set up slightly off the line of two closely spaced plumb wires; a tiny measured angle, scaled by side lengths, recovers the precise wire-to-wire azimuth for the underground traverse.', 'Two-wire azimuth transfer.', 'c1000016-0000-0000-0000-000000000016', '7a245639-e051-4c8c-9bf3-24aaea257ab1', 'surveying', ARRAY['buildout','module-22']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2240-0000-0000-0000-000000000005', 'Gyrotheodolite', 'A surveying instrument combining a theodolite with a gyroscope that senses Earth''s rotation to determine true north directly underground, independent of any shaft geometry — used to set or check underground azimuth.', 'Finds true north underground.', 'c1000016-0000-0000-0000-000000000016', '7a245639-e051-4c8c-9bf3-24aaea257ab1', 'surveying', ARRAY['buildout','module-22']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2240-0000-0000-0000-000000000006', 'Spad', 'A hook-eye nail driven into the roof (back) of a heading to fix an underground survey or layout station; a plumb bob hung from it brings the point down to instrument or sighting height.', 'Roof station you hang a bob from.', 'c1000016-0000-0000-0000-000000000016', '5068d3ab-7f1e-41d8-ba6e-cbc1864c54e3', 'surveying', ARRAY['buildout','module-22']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2240-0000-0000-0000-000000000007', 'Forced centering', 'An underground/precise traversing practice of interchanging tribrachs (instrument and targets) on permanently set tripods or wall brackets, eliminating repeated re-centering error over the many short legs.', 'Swap tribrachs, not re-center.', 'c1000016-0000-0000-0000-000000000016', '5068d3ab-7f1e-41d8-ba6e-cbc1864c54e3', 'surveying', ARRAY['buildout','module-22']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2240-0000-0000-0000-000000000008', 'Line and grade', 'The two pieces of layout the mine surveyor gives a heading: line is the horizontal direction to drive (set by spads or a laser), grade is the design slope of the floor/invert (set by grade pegs or a tilted laser).', 'Direction and slope for the miners.', 'c1000016-0000-0000-0000-000000000016', '5068d3ab-7f1e-41d8-ba6e-cbc1864c54e3', 'surveying', ARRAY['buildout','module-22']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2240-0000-0000-0000-000000000009', 'Incline grade', 'The slope of an inclined drift/decline, given as an angle θ = atan2(rise, run) in degrees or as a percent = rise/run × 100; a decline ramp is often specified in percent for haulage.', 'Angle or percent from rise and run.', 'c1000016-0000-0000-0000-000000000016', '5068d3ab-7f1e-41d8-ba6e-cbc1864c54e3', 'surveying', ARRAY['buildout','module-22']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2240-0000-0000-0000-000000000010', 'Mining-induced subsidence', 'The lowering of the ground surface caused by relaxation of overlying rock into voids left by underground extraction; ranges from broad sag troughs to sinkholes and step scarps, capable of damaging structures and utilities.', 'Ground sinks over the workings.', 'c1000016-0000-0000-0000-000000000016', '2a2f13a3-eaf6-424f-a469-c84dfae6951b', 'surveying', ARRAY['buildout','module-22']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2240-0000-0000-0000-000000000011', 'Monitoring epoch', 'One complete round of observations of a monitoring network at a point in time; comparing successive epochs reveals the vertical (settlement) and horizontal (strain) movement of each point.', 'One survey ''snapshot'' in time.', 'c1000016-0000-0000-0000-000000000016', '2a2f13a3-eaf6-424f-a469-c84dfae6951b', 'surveying', ARRAY['buildout','module-22']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2240-0000-0000-0000-000000000012', 'Average-end-area method', 'A volume method: cut parallel cross-sections spaced L apart, measure each end area, and take V = (A1 + A2)/2 × L between adjacent sections, summed along the body (stockpile, pit, or earthwork).', 'Mean of two end areas times spacing.', 'c1000016-0000-0000-0000-000000000016', '2a2f13a3-eaf6-424f-a469-c84dfae6951b', 'surveying', ARRAY['buildout','module-22']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2240-0000-0000-0000-000000000013', 'UAV volume survey', 'Using drone photogrammetry or LiDAR to build a dense 3D surface of a stockpile/pit and differencing it against a base surface to compute volume — fast, safe, and dense compared with hand cross-sections.', 'Drone surface differenced to a base.', 'c1000016-0000-0000-0000-000000000016', '2a2f13a3-eaf6-424f-a469-c84dfae6951b', 'surveying', ARRAY['buildout','module-22']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2240-0000-0000-0000-000000000014', 'Dimensional / industrial metrology', 'The application of surveying measurement science (angles, distances, coordinates, adjustment) to align and inspect machines and manufactured assemblies to micrometre-to-tenth-of-millimetre tolerances.', 'Surveying precision applied to machines.', 'c1000016-0000-0000-0000-000000000016', '1842b5e3-a8d9-43d7-9972-5b585eff182c', 'surveying', ARRAY['buildout','module-22']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2240-0000-0000-0000-000000000015', 'Large-scale metrology', 'Metrology of objects too big for a benchtop CMM — aircraft, turbines, ships, accelerators — using portable high-accuracy instruments (laser trackers, total stations, photogrammetry) in one reference frame.', 'Big parts a CMM can''t fit.', 'c1000016-0000-0000-0000-000000000016', '1842b5e3-a8d9-43d7-9972-5b585eff182c', 'surveying', ARRAY['buildout','module-22']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2240-0000-0000-0000-000000000016', 'Laser tracker (SMR)', 'A servo head that locks a laser onto a spherically mounted retroreflector and continuously reports its 3D coordinates to a few micrometres per metre, used for machine alignment and large-part inspection.', 'Follows a mirror-ball in 3D.', 'c1000016-0000-0000-0000-000000000016', '1842b5e3-a8d9-43d7-9972-5b585eff182c', 'surveying', ARRAY['buildout','module-22']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2240-0000-0000-0000-000000000017', 'Autocollimator', 'An optical instrument that measures very small angular deviations (tilt/twist) of a reflecting surface to fractions of an arc-second, used to check flatness, straightness, and squareness of machine elements.', 'Tiny angles to arc-seconds.', 'c1000016-0000-0000-0000-000000000016', '1842b5e3-a8d9-43d7-9972-5b585eff182c', 'surveying', ARRAY['buildout','module-22']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2240-0000-0000-0000-000000000018', 'Deformation monitoring survey', 'A survey that measures an object repeatedly over time (in epochs) to detect, quantify, and characterise movement — settlement, tilt, convergence, creep — relative to stable reference points.', 'Watch for movement over time.', 'c1000016-0000-0000-0000-000000000016', 'da502306-8208-4fd7-9910-5bbf852044ba', 'surveying', ARRAY['buildout','module-22']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2240-0000-0000-0000-000000000019', 'Reference vs. object points', 'Reference (datum) points sit on ground proven stable outside the deforming zone and define the frame; object (target) points are fixed to the structure/ground being watched. Movement is the change in object points relative to the reference frame.', 'Stable frame vs. watched targets.', 'c1000016-0000-0000-0000-000000000016', 'da502306-8208-4fd7-9910-5bbf852044ba', 'surveying', ARRAY['buildout','module-22']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2240-0000-0000-0000-000000000020', 'Statistical significance of movement', 'A computed displacement is treated as real deformation only when it exceeds the combined uncertainty of the two epochs (e.g., ≈ 2√2 σ at 95%); smaller apparent movement is measurement noise.', 'Bigger than the noise floor.', 'c1000016-0000-0000-0000-000000000016', 'da502306-8208-4fd7-9910-5bbf852044ba', 'surveying', ARRAY['buildout','module-22']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2240-0000-0000-0000-000000000021', 'Automated robotic total station monitoring', 'An ATS that cyclically sights an array of fixed prisms, computing sub-millimetre 3D positions every few minutes for continuous monitoring of dams, slopes, tunnels, and structures.', 'Robot cycles prisms automatically.', 'c1000016-0000-0000-0000-000000000016', 'da502306-8208-4fd7-9910-5bbf852044ba', 'surveying', ARRAY['buildout','module-22']::text[], true, 'approved', 'intermediate');
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2230-0000-0000-0000-000000000001', 'In a correlation (connection) survey down a vertical shaft, which quantity is the most difficult to transfer underground?', 'multiple_choice', '["Azimuth (orientation of the underground traverse)","Horizontal position (X, Y of a point)","Elevation of the shaft bottom","The temperature of the air"]'::jsonb, 'Azimuth (orientation of the underground traverse)', 'Position can be carried down by plumbing and elevation by taping/levelling the shaft, but a vertical shaft offers almost no horizontal geometry to fix direction, so transferring azimuth is the classic hard problem — small errors swing the far end of long drifts badly.', 'medium', 'c1000016-0000-0000-0000-000000000016', '7a245639-e051-4c8c-9bf3-24aaea257ab1', ARRAY['buildout','module-22']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2230-0000-0000-0000-000000000002', 'What is the purpose of a Weisbach triangle in shaft surveying?', 'multiple_choice', '["To recover the precise direction between two closely spaced plumb wires for azimuth transfer","To compute the volume of muck hoisted up the shaft","To level the shaft bottom to the surface benchmark","To measure the depth of the shaft"]'::jsonb, 'To recover the precise direction between two closely spaced plumb wires for azimuth transfer', 'Because two plumb wires hang very close together, a theodolite cannot occupy their line; setting up slightly off-line forms a very thin Weisbach triangle whose small measured angle, scaled by side lengths, gives the precise wire-to-wire azimuth that orients the underground traverse.', 'hard', 'c1000016-0000-0000-0000-000000000016', '7a245639-e051-4c8c-9bf3-24aaea257ab1', ARRAY['buildout','module-22']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2230-0000-0000-0000-000000000003', 'A gyrotheodolite establishes underground azimuth by:', 'multiple_choice', '["Sensing the Earth''s rotation to find true north directly","Receiving GNSS signals at the shaft bottom","Reading a magnetic compass corrected for declination","Measuring the sway of the plumb wires"]'::jsonb, 'Sensing the Earth''s rotation to find true north directly', 'A gyrotheodolite combines a theodolite with a gyroscope that senses Earth''s rotation to find true north independent of any shaft geometry or surface tie — invaluable underground and in long tunnels, and a strong check on a two-wire transfer. GNSS does not work underground and a magnetic compass is unreliable near steel and ore.', 'medium', 'c1000016-0000-0000-0000-000000000016', '7a245639-e051-4c8c-9bf3-24aaea257ab1', ARRAY['buildout','module-22']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2230-0000-0000-0000-000000000004', 'Optical/laser shaft plumbing (an autoplumb) is often preferred over suspended plumb wires because it avoids wire sway and is faster.', 'true_false', '["True","False"]'::jsonb, 'True', 'A vertical-collimating autoplumb or plumbing laser projects a steady vertical line down the shaft to a target, avoiding the sway, damping tanks, and time of suspended wires, while still delivering known surface coordinates to the shaft bottom.', 'easy', 'c1000016-0000-0000-0000-000000000016', '7a245639-e051-4c8c-9bf3-24aaea257ab1', ARRAY['buildout','module-22']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2230-0000-0000-0000-000000000005', 'Why are underground survey stations commonly fixed in the roof (back) with a spad rather than in the floor?', 'multiple_choice', '["The floor is disturbed by traffic, muck, and water, while a roof spad is stable","Roof stations are required by GNSS","Floor stations cannot be levelled","It is impossible to drive a nail into a mine floor"]'::jsonb, 'The floor is disturbed by traffic, muck, and water, while a roof spad is stable', 'The floor of a heading is churned by equipment, muck, and water, so a roof spad gives a far more stable station; a plumb bob hung from it brings the point down to instrument or sighting height.', 'easy', 'c1000016-0000-0000-0000-000000000016', '5068d3ab-7f1e-41d8-ba6e-cbc1864c54e3', ARRAY['buildout','module-22']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2230-0000-0000-0000-000000000006', 'An inclined drift rises 5.0 m vertically over a horizontal run of 80.0 m. Its grade as a percent is approximately:', 'multiple_choice', '["6.3%","1.6%","16%","3.6%"]'::jsonb, '6.3%', 'Percent grade = rise/run × 100 = 5.0/80.0 × 100 = 6.25% ≈ 6.3%. As an angle it is atan2(5.0, 80.0) ≈ 3.58°.', 'medium', 'c1000016-0000-0000-0000-000000000016', '5068d3ab-7f1e-41d8-ba6e-cbc1864c54e3', ARRAY['buildout','module-22']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2230-0000-0000-0000-000000000007', 'What does ''forced centering'' achieve in underground traversing?', 'multiple_choice', '["It reduces centering error over many short legs by interchanging tribrachs on fixed setups","It forces the instrument to read true north","It increases the measured distance accuracy of the EDM","It prevents the plumb bob from swinging"]'::jsonb, 'It reduces centering error over many short legs by interchanging tribrachs on fixed setups', 'Underground legs are short, so repeated re-centering would inject large relative error. Swapping instrument and target tribrachs on permanently set tripods/brackets keeps everything on the same forced center, minimizing centering error.', 'medium', 'c1000016-0000-0000-0000-000000000016', '5068d3ab-7f1e-41d8-ba6e-cbc1864c54e3', ARRAY['buildout','module-22']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2230-0000-0000-0000-000000000008', 'Which best describes how a surveyor gives ''line'' to a driving heading?', 'multiple_choice', '["Sets spads (or a laser) on the design centerline for the miners to sight or follow to the face","Marks only the elevation of the floor","Hands the miners the coordinates of the orebody","Levels the face to the surface benchmark"]'::jsonb, 'Sets spads (or a laser) on the design centerline for the miners to sight or follow to the face', 'Line is the horizontal direction to drive: the surveyor sets two or three centerline spads (or a laser projecting the line), and the miners keep the face on that line. Grade (slope) is given separately by grade pegs or a tilted laser.', 'easy', 'c1000016-0000-0000-0000-000000000016', '5068d3ab-7f1e-41d8-ba6e-cbc1864c54e3', ARRAY['buildout','module-22']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2230-0000-0000-0000-000000000009', 'Why must the reference benchmarks for a subsidence monitoring survey lie outside the subsidence basin?', 'multiple_choice', '["If a ''stable'' benchmark is itself sinking, the survey will under-report the true movement","Benchmarks inside the basin are illegal","It makes the levelling loop shorter","GNSS does not work inside a subsidence basin"]'::jsonb, 'If a ''stable'' benchmark is itself sinking, the survey will under-report the true movement', 'Subsidence is measured relative to the datum. A datum benchmark inside the influence zone is itself moving, so the measured settlement is referenced to a moving frame and is too small — the datum must be proven stable and outside the basin.', 'medium', 'c1000016-0000-0000-0000-000000000016', '2a2f13a3-eaf6-424f-a469-c84dfae6951b', ARRAY['buildout','module-22']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2230-0000-0000-0000-000000000010', 'Two cross-sections through a waste stockpile have areas of 40 m² and 60 m² and are spaced 25 m apart. By the average-end-area method, the volume between them is:', 'multiple_choice', '["1,250 m³","1,000 m³","2,500 m³","100 m³"]'::jsonb, '1,250 m³', 'V = (A1 + A2)/2 × L = (40 + 60)/2 × 25 = 50 × 25 = 1,250 m³.', 'medium', 'c1000016-0000-0000-0000-000000000016', '2a2f13a3-eaf6-424f-a469-c84dfae6951b', ARRAY['buildout','module-22']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2230-0000-0000-0000-000000000011', 'UAV (drone) photogrammetry computes a stockpile volume by:', 'multiple_choice', '["Building a dense 3D surface of the pile and differencing it against a base surface","Weighing the pile from the air","Measuring the pile''s shadow length","Counting the number of trucks that dumped it"]'::jsonb, 'Building a dense 3D surface of the pile and differencing it against a base surface', 'A UAV photogrammetry (or LiDAR) survey produces a dense 3D surface of the stockpile; software integrates the height difference between that surface and a base/ground surface over the footprint to give the volume — fast, dense, and safe.', 'easy', 'c1000016-0000-0000-0000-000000000016', '2a2f13a3-eaf6-424f-a469-c84dfae6951b', ARRAY['buildout','module-22']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2230-0000-0000-0000-000000000012', 'Satellite InSAR is useful for subsidence monitoring because it measures wide-area, millimetre-level movement without requiring any ground marks.', 'true_false', '["True","False"]'::jsonb, 'True', 'InSAR compares radar phase from repeated satellite passes to map line-of-sight ground movement at millimetre level over wide areas, needing no installed targets — though it is limited by coherence, weather, and line-of-sight geometry.', 'easy', 'c1000016-0000-0000-0000-000000000016', '2a2f13a3-eaf6-424f-a469-c84dfae6951b', ARRAY['buildout','module-22']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2230-0000-0000-0000-000000000013', 'A laser tracker determines the position of a large machine component by:', 'multiple_choice', '["Locking a laser onto a spherically mounted retroreflector and reporting its 3D coordinates","Photographing the part from two angles only","Measuring the magnetic field of the steel","Weighing the component on a load cell"]'::jsonb, 'Locking a laser onto a spherically mounted retroreflector and reporting its 3D coordinates', 'A laser tracker servo-locks an interferometer/ADM laser onto a spherically mounted retroreflector (SMR) and continuously reports the SMR''s 3D coordinates to a few micrometres per metre as it is moved over the part.', 'easy', 'c1000016-0000-0000-0000-000000000016', '1842b5e3-a8d9-43d7-9972-5b585eff182c', ARRAY['buildout','module-22']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2230-0000-0000-0000-000000000014', 'An autocollimator is best suited to measuring:', 'multiple_choice', '["Very small angular deviations (tilt/twist) of a reflecting surface to fractions of an arc-second","Long horizontal distances to kilometre range","The 3D point cloud of an entire room","Atmospheric pressure"]'::jsonb, 'Very small angular deviations (tilt/twist) of a reflecting surface to fractions of an arc-second', 'An autocollimator measures tiny angular deviations of a reflecting face to fractions of an arc-second, used to check flatness, straightness, and squareness of machine elements — not distances or full surfaces.', 'medium', 'c1000016-0000-0000-0000-000000000016', '1842b5e3-a8d9-43d7-9972-5b585eff182c', ARRAY['buildout','module-22']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2230-0000-0000-0000-000000000015', 'Why are industrial metrology measurements referenced to 20 °C and taken when the structure is thermally stable?', 'multiple_choice', '["Because thermal expansion (ΔL = αLΔT) changes large steel dimensions enough to exceed micrometre tolerances","Because lasers only work at 20 °C","Because surveyors prefer cool rooms","Because steel does not expand below 20 °C"]'::jsonb, 'Because thermal expansion (ΔL = αLΔT) changes large steel dimensions enough to exceed micrometre tolerances', 'Steel expands about 11.7 µm per metre per °C, so a 10 m assembly grows over 0.1 mm per 1 °C — larger than the tolerance. Measurements are referenced to 20 °C, taken at thermal equilibrium, and corrected for temperature.', 'medium', 'c1000016-0000-0000-0000-000000000016', '1842b5e3-a8d9-43d7-9972-5b585eff182c', ARRAY['buildout','module-22']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2230-0000-0000-0000-000000000016', 'In a deformation monitoring network, the role of the reference (datum) points is to:', 'multiple_choice', '["Provide a stable frame, outside the deforming zone, against which object-point movement is measured","Mark the most likely failure surface","Carry the GNSS antenna power supply","Replace the need for least-squares adjustment"]'::jsonb, 'Provide a stable frame, outside the deforming zone, against which object-point movement is measured', 'Reference points sit on proven-stable ground outside the deforming zone and define the frame; object (target) points are fixed to the structure being watched, and their movement is expressed relative to the reference frame.', 'easy', 'c1000016-0000-0000-0000-000000000016', 'da502306-8208-4fd7-9910-5bbf852044ba', ARRAY['buildout','module-22']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2230-0000-0000-0000-000000000017', 'An object point moves ΔE = 9 mm east and ΔN = 12 mm north between two epochs. Its resultant horizontal displacement is:', 'multiple_choice', '["15 mm","21 mm","10.5 mm","3 mm"]'::jsonb, '15 mm', 'δ = hypot(ΔE, ΔN) = sqrt(9² + 12²) = sqrt(81 + 144) = sqrt(225) = 15 mm.', 'medium', 'c1000016-0000-0000-0000-000000000016', 'da502306-8208-4fd7-9910-5bbf852044ba', ARRAY['buildout','module-22']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2230-0000-0000-0000-000000000018', 'When should an apparent inter-epoch movement of a monitored point be reported as real deformation?', 'multiple_choice', '["Only when it exceeds the combined measurement uncertainty (statistically significant)","Whenever any nonzero change is computed","Only after the structure has visibly failed","Whenever the weather changes"]'::jsonb, 'Only when it exceeds the combined measurement uncertainty (statistically significant)', 'Every measurement has noise, so a displacement is treated as real deformation only when it exceeds the combined uncertainty of the two epochs. Reporting smaller apparent movement causes false alarms; failing to detect real movement is dangerous.', 'hard', 'c1000016-0000-0000-0000-000000000016', 'da502306-8208-4fd7-9910-5bbf852044ba', ARRAY['buildout','module-22']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2230-0000-0000-0000-000000000019', 'Which instrument provides automated, near-continuous sub-millimetre 3D monitoring of an array of prisms on a pit slope or dam?', 'multiple_choice', '["An automated (robotic) total station","A hand level","A magnetic compass","A measuring wheel"]'::jsonb, 'An automated (robotic) total station', 'A robotic/automated total station cyclically sights fixed prisms and computes sub-millimetre 3D positions every few minutes, the workhorse for continuous monitoring of dams, slopes, tunnels, and structures.', 'easy', 'c1000016-0000-0000-0000-000000000016', 'da502306-8208-4fd7-9910-5bbf852044ba', ARRAY['buildout','module-22']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2230-0000-0000-0000-000000000020', 'Which statement best captures the unifying theme of mining and industrial surveying?', 'multiple_choice', '["Extending precise control and measurement into difficult environments — underground, large machines, and moving structures","Recording only property boundaries for deeds","Computing parcel areas for taxation","Mapping navigable waterways and tidal datums"]'::jsonb, 'Extending precise control and measurement into difficult environments — underground, large machines, and moving structures', 'Mining and industrial surveying take core surveying skills — control, traversing, levelling, adjustment, volumes — into challenging settings: underground workings with no GNSS, micrometre machine alignment, and time-dependent deformation, each demanding special methods and instruments.', 'medium', 'c1000016-0000-0000-0000-000000000016', NULL, ARRAY['buildout','module-22']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
