INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee2260-0000-0000-0000-000000000001', 'An inclined drift rises {{rise:f2}} m vertically over a horizontal run of {{run}} m. What is its grade expressed as an angle of inclination (degrees)?', 'numeric_input', '[]'::jsonb, '0', 'The angle of inclination is θ = atan2(rise, run) = atan2({{rise:f2}}, {{run}}) = {{_answer}}°. (As a percent grade this is rise/run × 100 = {{rise:f2}}/{{run}} × 100.)', 'easy', 'c1000016-0000-0000-0000-000000000016', NULL, ARRAY['buildout','module-22','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee2250-0000-0000-0000-000000000001', 0.05);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee2260-0000-0000-0000-000000000002', 'Two parallel cross-sections through a stockpile have areas A1 = {{A1}} m² and A2 = {{A2}} m² and are spaced L = {{L}} m apart. Using the average-end-area method, what is the volume (m³) of material between them?', 'numeric_input', '[]'::jsonb, '0', 'The average-end-area volume is V = (A1 + A2)/2 × L = ({{A1}} + {{A2}})/2 × {{L}} = {{_answer}} m³.', 'medium', 'c1000016-0000-0000-0000-000000000016', NULL, ARRAY['buildout','module-22','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee2250-0000-0000-0000-000000000002', 0.5);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee2260-0000-0000-0000-000000000003', 'Two plumb wires hang in a shaft forming a baseline of length b = {{b:f2}} m. At the shaft bottom the far wire is found to be offset perpendicular to the line by e = {{e:f3}} m. If the known surface azimuth of the baseline is {{az:f2}}°, what is the corrected underground azimuth of the baseline (degrees)? Add the small correction angle.', 'numeric_input', '[]'::jsonb, '0', 'The wire offset over the baseline gives a correction angle δ = atan2(e, b) = atan2({{e:f3}}, {{b:f2}}) = {{corr:f3}}°. Applied to the surface azimuth, the underground baseline azimuth is {{az:f2}}° + {{corr:f3}}° = {{_answer}}°.', 'hard', 'c1000016-0000-0000-0000-000000000016', NULL, ARRAY['buildout','module-22','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee2250-0000-0000-0000-000000000003', 0.01);
