BEGIN;
DELETE FROM question_bank     WHERE module_id='c1000016-0000-0000-0000-000000000016' AND 'buildout' = ANY(tags);
DELETE FROM flashcards        WHERE module_id='c1000016-0000-0000-0000-000000000016' AND 'buildout' = ANY(tags);
DELETE FROM problem_templates WHERE module_id='c1000016-0000-0000-0000-000000000016' AND created_by='buildout:m22';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['Mine surveying ties a surface control network to underground workings so that excavations are dug to the correct position, grade, and orientation','A correlation (connection) survey transfers position and azimuth down a shaft; orientation is the difficult part because a vertical shaft gives little geometry to fix direction','Shaft plumbing drops one or two physical/optical plumb lines down the shaft to carry coordinates underground','Azimuth is transferred by the two-wire (Weisbach) method or, independently, by a gyrotheodolite that finds true north underground']::text[], learning_objectives=ARRAY['Define mine surveying and distinguish surface from underground control','Explain how surface control is transferred underground (correlation surveys) and why it is the hardest problem in mine surveying','Describe shaft plumbing methods (wire plumbing, optical/laser plumbing) and the Weisbach triangle for azimuth transfer','State the role of the gyrotheodolite in establishing underground azimuth independent of surface ties']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='7a245639-e051-4c8c-9bf3-24aaea257ab1';
DELETE FROM lesson_blocks WHERE lesson_id='7a245639-e051-4c8c-9bf3-24aaea257ab1';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['Underground traverses use roof or floor stations (often hanging plumb bobs from roof spads) with short, obstructed sights and forced centering','Line and grade are given to the miners with a laser line on the line and grade pegs/spads to the design slope','Grade of an incline = atan2(rise, run) in degrees, or rise/run × 100 as a percent','Periodic gyro azimuth observations bound the orientation error that otherwise accumulates over long drives']::text[], learning_objectives=ARRAY['Run an underground traverse using roof/floor stations, hanging plumb bobs, and forced centering','Set line and grade for a heading using spads, the laser line, and grade pegs','Compute the grade (slope) of an inclined drift or incline from rise and run','Describe how a gyrotheodolite re-orients a traverse and limits azimuth error over long drives']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='5068d3ab-7f1e-41d8-ba6e-cbc1864c54e3';
DELETE FROM lesson_blocks WHERE lesson_id='5068d3ab-7f1e-41d8-ba6e-cbc1864c54e3';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['Underground extraction lowers the overlying ground (subsidence); monitoring detects and quantifies it to protect surface structures and the public','Subsidence is observed by repeated precise levelling/GNSS over fixed monitoring points and reported as movement between epochs','Stockpile and pit volumes are computed by average end area between cross-sections, or by differencing surfaces from UAV/laser scans','Modern monitoring blends precise levelling, GNSS, robotic total stations, UAV photogrammetry/LiDAR, and satellite InSAR']::text[], learning_objectives=ARRAY['Explain mining-induced subsidence and the surface features it produces (sag, troughs, sinkholes)','Lay out and observe a subsidence monitoring line and compute vertical movement between epochs','Compute stockpile and pit volumes by the average-end-area method and by UAV/surface comparison','Describe how precise levelling, total stations, GNSS, UAV photogrammetry, and InSAR are combined for monitoring']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='2a2f13a3-eaf6-424f-a469-c84dfae6951b';
DELETE FROM lesson_blocks WHERE lesson_id='2a2f13a3-eaf6-424f-a469-c84dfae6951b';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['Industrial / dimensional metrology applies surveying principles to align and measure machines and assemblies to sub-millimetre (often micrometre) tolerances','Large-scale metrology covers objects too big for a CMM — aircraft, turbines, accelerators, ship hulls — using trackers and total stations','Laser trackers measure 3D coordinates of a moving retroreflector (SMR) to micrometre precision; laser lines and autocollimators verify straightness and squareness','The reference frame (datum) and environmental control (temperature) dominate the achievable accuracy']::text[], learning_objectives=ARRAY['Define industrial / dimensional metrology and large-scale metrology and distinguish it from ordinary surveying','Describe laser-tracker, laser-line, and autocollimation methods for machine alignment','Explain the precision and reference-frame demands of aligning large machines and assemblies','Relate alignment tolerances (flatness, straightness, level, coaxiality) to the instruments used to verify them']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='1842b5e3-a8d9-43d7-9972-5b585eff182c';
DELETE FROM lesson_blocks WHERE lesson_id='1842b5e3-a8d9-43d7-9972-5b585eff182c';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=45, key_takeaways=ARRAY['Deformation monitoring repeatedly surveys an object to detect and quantify movement over time relative to stable reference points','It separates stable reference (datum) points from object points; only movement larger than survey uncertainty is real','Automated robotic total stations, GNSS, InSAR, tiltmeters, and crackmeters provide near-continuous monitoring of dams, slopes, pits, and structures','Results are judged against alert/alarm thresholds, with redundancy and adjustment to avoid false alarms and missed movement']::text[], learning_objectives=ARRAY['Define a deformation monitoring survey and distinguish reference (datum) points from object (target) points','Design an epoch-based monitoring scheme and test movement for statistical significance','Apply geodetic and geotechnical sensors (robotic total stations, GNSS, InSAR, prisms, tiltmeters, crackmeters) appropriately','Interpret monitoring results against alert/alarm thresholds and report movement responsibly']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='da502306-8208-4fd7-9910-5bbf852044ba';
DELETE FROM lesson_blocks WHERE lesson_id='da502306-8208-4fd7-9910-5bbf852044ba';
  'eeee2250-0000-0000-0000-000000000001', 'Grade (slope) of an inclined drift', 'Compute the grade of an inclined drift/decline from its vertical rise and horizontal run, as an angle in degrees and (optionally) as a percent.', 'Mining & Industrial Surveying — Inclines', 'Grade / slope', 'numeric_input', 'easy', 'An inclined drift rises {{rise:f2}} m vertically over a horizontal run of {{run}} m. What is its grade expressed as an angle of inclination (degrees)?', 'toDeg(atan2(rise,run))', '{"decimals":2,"unit":"deg","tolerance":0.05}', '[{"name":"rise","type":"float","min":2,"max":20,"decimals":2},{"name":"run","type":"integer","min":40,"max":200}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Take the arctangent of rise over run","formula":"θ = atan2(rise, run)","calculation_template":"atan2({{rise:f2}}, {{run}})"},{"step_number":2,"title":"Convert to degrees","result_template":"θ = {{_answer}}°"}]'::jsonb, '{"method":"none"}'::jsonb, 'The angle of inclination is θ = atan2(rise, run) = atan2({{rise:f2}}, {{run}}) = {{_answer}}°. (As a percent grade this is rise/run × 100 = {{rise:f2}}/{{run}} × 100.)', 'c1000016-0000-0000-0000-000000000016', ARRAY['buildout','module-22','practice']::text[], true, 'buildout:m22');
  'eeee2250-0000-0000-0000-000000000002', 'Stockpile volume by average end area', 'Compute the volume of material between two parallel cross-sections of a stockpile or pit using the average-end-area method.', 'Mining & Industrial Surveying — Volumes', 'Average end area', 'numeric_input', 'medium', 'Two parallel cross-sections through a stockpile have areas A1 = {{A1}} m² and A2 = {{A2}} m² and are spaced L = {{L}} m apart. Using the average-end-area method, what is the volume (m³) of material between them?', '(A1+A2)/2*L', '{"decimals":1,"unit":"m^3","tolerance":0.5}', '[{"name":"A1","type":"integer","min":20,"max":120},{"name":"A2","type":"integer","min":20,"max":120},{"name":"L","type":"integer","min":10,"max":50}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Average the two end areas","formula":"(A1 + A2) / 2","calculation_template":"({{A1}} + {{A2}}) / 2"},{"step_number":2,"title":"Multiply by the spacing","result_template":"V = ({{A1}} + {{A2}})/2 × {{L}} = {{_answer}} m³"}]'::jsonb, '{"method":"none"}'::jsonb, 'The average-end-area volume is V = (A1 + A2)/2 × L = ({{A1}} + {{A2}})/2 × {{L}} = {{_answer}} m³.', 'c1000016-0000-0000-0000-000000000016', ARRAY['buildout','module-22','practice']::text[], true, 'buildout:m22');
  'eeee2250-0000-0000-0000-000000000003', 'Azimuth transfer down a shaft (offset)', 'Recover the underground baseline azimuth from a known surface azimuth and a small lateral offset of the far wire over a baseline length (simplified Weisbach-style transfer).', 'Mining & Industrial Surveying — Correlation Survey', 'Azimuth transfer', 'numeric_input', 'hard', 'Two plumb wires hang in a shaft forming a baseline of length b = {{b:f2}} m. At the shaft bottom the far wire is found to be offset perpendicular to the line by e = {{e:f3}} m. If the known surface azimuth of the baseline is {{az:f2}}°, what is the corrected underground azimuth of the baseline (degrees)? Add the small correction angle.', 'az + toDeg(atan2(e,b))', '{"decimals":3,"unit":"deg","tolerance":0.01}', '[{"name":"b","type":"float","min":3,"max":8,"decimals":2},{"name":"e","type":"float","min":-0.05,"max":0.05,"decimals":3},{"name":"az","type":"float","min":10,"max":350,"decimals":2}]'::jsonb, '[{"name":"corr","formula":"toDeg(atan2(e,b))"}]'::jsonb, '[{"step_number":1,"title":"Compute the small correction angle","formula":"δ = atan2(e, b)","calculation_template":"atan2({{e:f3}}, {{b:f2}}) = {{corr:f3}}°"},{"step_number":2,"title":"Apply to the surface azimuth","result_template":"Azimuth = {{az:f2}}° + {{corr:f3}}° = {{_answer}}°"}]'::jsonb, '{"method":"none"}'::jsonb, 'The wire offset over the baseline gives a correction angle δ = atan2(e, b) = atan2({{e:f3}}, {{b:f2}}) = {{corr:f3}}°. Applied to the surface azimuth, the underground baseline azimuth is {{az:f2}}° + {{corr:f3}}° = {{_answer}}°.', 'c1000016-0000-0000-0000-000000000016', ARRAY['buildout','module-22','practice']::text[], true, 'buildout:m22');
COMMIT;
SELECT 'm22 Mining and Industrial Surveying: ' || (SELECT count(*) FROM lesson_blocks lb JOIN learning_lessons l ON l.id=lb.lesson_id WHERE l.module_id='c1000016-0000-0000-0000-000000000016') || ' blocks.' AS status;